import sys
it = iter(sys.stdin.read().split())
num = next(it)
target = int(next(it))

def add_operators(num, target):
    res = []
    def dfs(i, path, value, prev):
        if i == len(num):
            if value == target:
                res.append(path)
            return
        for j in range(i, len(num)):
            if j != i and num[i] == '0':
                break
            cur = int(num[i:j+1])
            if i == 0:
                dfs(j+1, path + str(cur), cur, cur)
            else:
                dfs(j+1, path + '+' + str(cur), value + cur, cur)
                dfs(j+1, path + '-' + str(cur), value - cur, -cur)
                dfs(j+1, path + '*' + str(cur), value - prev + prev * cur, prev * cur)
    dfs(0, '', 0, 0)
    return res

res = add_operators(num, target)
if res:
    for expr in res:
        print(expr)
else:
    print('NONE')

