#include <bits/stdc++.h>
using namespace std;
int main() {
    string num;
    cin >> num;
    long long target;
    cin >> target;
    vector<string> res;
    function<void(int, string, long long, long long)> dfs = [&](int i, string path, long long value, long long prev) {
        if (i == num.size()) {
            if (value == target) {
                res.push_back(path);
            }
            return;
        }
        for (int j = i; j < num.size(); j++) {
            if (j != i && num[i] == '0') {
                break;
            }
            string cur = num.substr(i, j - i + 1);
            long long cur_val = stoll(cur);
            if (i == 0) {
                dfs(j + 1, cur, cur_val, cur_val);
            } else {
                dfs(j + 1, path + '+' + cur, value + cur_val, cur_val);
                dfs(j + 1, path + '-' + cur, value - cur_val, -cur_val);
                dfs(j + 1, path + '*' + cur, value - prev + prev * cur_val, prev * cur_val);
            }
        }
    };
    dfs(0, "", 0, 0);
    if (res.size()) {
        for (const auto& expr : res) {
            cout << expr << '\n';
        }
    } else {
        cout << "NONE" << '\n';
    }
    return 0;
}
